const input = $input.first().json;

// Safety check
if (!input.articles || !Array.isArray(input.articles)) {
  return [];
}

// Simple hash function
function createId(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return hash.toString();
}

return input.articles
  .filter(article => {
    const title = article.title?.toLowerCase() || "";

    // remove junk
    if (!title) return false;
    if (title.includes("news about")) return false;

    return true;
  })
  .map(article => {
    // Clean for stable ID
    const cleanTitle = (article.title || "").trim().toLowerCase();
    const cleanLink = (article.link || "").split("?")[0];

    const uniqueString = cleanTitle + cleanLink;

    return {
      json: {
        ...article,
        id: createId(uniqueString),
        company: input.company
      }
    };
  });

// 1. Get the current loop item from the input array
const inputData = $input.item.json;

// 2. Identify the nested search results (handling the empty key "")
const searchBatches = inputData[""] || [];

// 3. Extract and map articles from all news_results batches
let aggregatedArticles = [];

searchBatches.forEach(batch => {
  if (batch.news_results) {
    const mapped = batch.news_results.map(n => ({
      title: n.title || "No Title",
      source: n.source?.name || "Unknown Source",
      link: n.link || "",
      date: n.date || "Recent"
    }));
    aggregatedArticles = aggregatedArticles.concat(mapped);
  }
});

// 5. Return the structured object for the Aggregate node
return [
  {
    json: {
      articles: aggregatedArticles,
    }
  }
];
